import { describe, expect, it } from 'vitest';

import {
  adist,
  assessGaitLeak,
  coarseP,
  coarseQ,
  FootstepGaitLeakMaster,
  fpDistance,
  gaitLeaks,
  mismatchPenalty,
  walkA1,
  walkA2,
  walkB,
  type GaitSignature,
} from '../src/footstep-gait-leak';

describe('adist (mirrors adist_self / adist_comm)', () => {
  it('is zero at a point with itself', () => {
    for (const a of [0, 1, 12, 50]) {
      expect(adist(a, a)).toBe(0);
    }
  });

  it('is the absolute difference and symmetric', () => {
    expect(adist(50, 51)).toBe(1);
    expect(adist(51, 50)).toBe(1);
    expect(adist(12, 35)).toBe(23);
    expect(adist(35, 12)).toBe(23);
  });

  it('saturates at zero (Nat truncated subtraction)', () => {
    expect(adist(0, 0)).toBe(0);
    expect(Math.max(0, 4 - 9)).toBe(0);
  });
});

describe('fpDistance (mirrors fpDistance / fpDistance_self)', () => {
  it('is zero from a signature to itself (self-consistency)', () => {
    expect(fpDistance(walkA1, walkA1)).toBe(0);
    expect(fpDistance(walkB, walkB)).toBe(0);
    expect(fpDistance(coarseP, coarseP)).toBe(0);
  });

  it('is the summed pointwise adist of aligned gait features', () => {
    // 1 + 1 + 0 + 1 = 3
    expect(fpDistance(walkA1, walkA2)).toBe(3);
    // 12 + 12 + 23 + 18 = 65
    expect(fpDistance(walkA1, walkB)).toBe(65);
    // 0 + 0 + 0 + 1 = 1
    expect(fpDistance(coarseP, coarseQ)).toBe(1);
  });

  it('returns the large mismatch sentinel on a length mismatch', () => {
    expect(fpDistance([1, 2, 3], [1, 2])).toBe(mismatchPenalty);
    expect(fpDistance([], [0])).toBe(mismatchPenalty);
    expect(mismatchPenalty).toBeGreaterThan(65);
  });
});

describe('gaitLeaks (mirrors gaitLeaksB / GaitLeakPresent — separability is the leak)', () => {
  it('fires (leak present) when distinct gaits separate beyond sepThreshold', () => {
    // mirrors distinct_gaits_leakB
    expect(gaitLeaks(walkA1, walkB, { sepThreshold: 12 })).toBe(true);
  });

  it('does not fire on two walks of the same person', () => {
    // mirrors same_person_not_leak
    expect(gaitLeaks(walkA1, walkA2, { sepThreshold: 12 })).toBe(false);
  });

  it('does not fire on indistinguishable coarse gaits', () => {
    // mirrors indistinct_gaits_not_flagged
    expect(gaitLeaks(coarseP, coarseQ, { sepThreshold: 12 })).toBe(false);
  });
});

describe('promotion check: assessGaitLeak (leak-detector polarity)', () => {
  it('admits a re-identification LEAK when gaits are distinguishable (separation > sepThreshold)', () => {
    // mirrors distinct_gaits_leak: admitted = leak present, warn the user
    const a = assessGaitLeak(walkA1, walkB, { intraTol: 4, sepThreshold: 12 });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.leaks).toBe(true);
    expect(a.safe).toBe(false);
    expect(a.distance).toBe(65);
    expect(a.limitation).toBe('none');
  });

  it('withholds (SAFE) when gaits are indistinguishable within intraTol', () => {
    // mirrors indistinct_gaits_safe
    const a = assessGaitLeak(coarseP, coarseQ, { intraTol: 4, sepThreshold: 12 });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('indistinguishable_safe');
    expect(a.safe).toBe(true);
    expect(a.leaks).toBe(false);
    expect(a.distance).toBe(1);
  });

  it('withholds (SAFE) for two walks of the same person', () => {
    const a = assessGaitLeak(walkA1, walkA2, { intraTol: 4, sepThreshold: 12 });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('indistinguishable_safe');
    expect(a.distance).toBe(3);
  });

  it('reports observation_only in the ambiguous margin (intraTol < d <= sepThreshold)', () => {
    // distance 3 is above intraTol 2 but not beyond sepThreshold 12
    const a = assessGaitLeak(walkA1, walkA2, { intraTol: 2, sepThreshold: 12 });
    expect(a.outcome).toBe('observation_only');
    expect(a.limitation).toBe('ambiguous_margin');
    expect(a.leaks).toBe(false);
    expect(a.safe).toBe(false);
    expect(a.distance).toBe(3);
  });

  it('admits a LEAK at the boundary (distance just over sepThreshold)', () => {
    // distance 3, sepThreshold 2 -> leak
    const a = assessGaitLeak(walkA1, walkA2, { intraTol: 1, sepThreshold: 2 });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.distance).toBe(3);
  });

  it('treats a length mismatch as a separated (leaking) pair', () => {
    const a = assessGaitLeak(walkA1, [50, 18, 12], { intraTol: 4, sepThreshold: 12 });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.distance).toBe(mismatchPenalty);
    expect(a.leaks).toBe(true);
  });

  it('never identifies or re-identifies a person — it only flags separability', () => {
    const a = assessGaitLeak(walkA1, walkB, { intraTol: 4, sepThreshold: 12 });
    expect(Object.keys(a).sort()).toEqual(
      ['distance', 'leaks', 'limitation', 'outcome', 'safe', 'summary'].sort(),
    );
    const probe: GaitSignature = walkA1;
    expect(probe.length).toBe(4);
  });
});

describe('FootstepGaitLeakMaster (mirrors gait_leak_master)', () => {
  it('every boundary witness holds', () => {
    expect(FootstepGaitLeakMaster.fpDistanceSelfZero).toBe(true);
    expect(FootstepGaitLeakMaster.samePersonTight).toBe(true);
    expect(FootstepGaitLeakMaster.gaitsWellSeparated).toBe(true);
    expect(FootstepGaitLeakMaster.distinctGaitsLeak).toBe(true);
    expect(FootstepGaitLeakMaster.distinctGaitsLeakB).toBe(true);
    expect(FootstepGaitLeakMaster.samePersonNotLeak).toBe(true);
    expect(FootstepGaitLeakMaster.indistinctGaitsSafe).toBe(true);
    expect(FootstepGaitLeakMaster.indistinctGaitsNotFlagged).toBe(true);
  });
});
